const prev = $('Build Bucket Key').first().json;
const incrOut = $json;
const count = typeof incrOut[prev.key] === 'number' ? incrOut[prev.key] : 0;
const allowed = count <= prev.limit;
return [{ json: { allowed, scope: prev.scope, count, limit: prev.limit } }];
